import argparse, re
from pathlib import Path

CAPS = ['PA','PF','TO','IJ','EI']

def audit(log_path, missing=False):
    text = Path(log_path).read_text()
    steps = re.split(r'\n(?=Step \d+)', text)
    counts = {c: [] for c in CAPS}
    unlabeled = []
    for step in steps:
        found = [c for c in CAPS
                 if f'[{c}]' in step]
        for c in found:
            ctx = re.search(
                rf'.{{0,60}}\[{c}\].{{0,60}}', step)
            counts[c].append(
                ctx.group() if ctx else step[:80])
        if not found:
            unlabeled.append(step[:60])
    if missing:
        for s in unlabeled: print('UNLABELED:', s)
    else:
        for c in CAPS:
            ex = counts[c][0] if counts[c] else '—'
            print(f'| {c} | {len(counts[c])} | {ex} |')
